import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

class Solution {
    // Helper class to hold cost and peak count
    static class Result {
        long cost;
        int count;

        public Result(long cost, int count) {
            this.cost = cost;
            this.count = count;
        }
    }

    /**
     * Solves the problem by reducing it to Minimum Weight Independent Set (MWIS) on a Cycle Graph.
     * The cost for an element i is pre-calculated based on the original values of its neighbors.
     * We use DP to solve MWIS on the resulting linear arrays derived from breaking the cycle.
     */
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (k == 0) return 0;

        // 1. Check the structural limit on peaks: max peaks <= floor(N/2)
        if (k > n / 2) {
            return -1;
        }

        // 2. Pre-calculate costs
        long[] costs = new long[n];
        for (int i = 0; i < n; i++) {
            // Circular neighbors
            int prevIdx = (i - 1 + n) % n;
            int nextIdx = (i + 1) % n;

            long neighborMax = Math.max(nums[prevIdx], nums[nextIdx]);
            // Required value is neighborMax + 1.
            long requiredValue = neighborMax + 1;

            // Cost is the increase needed.
            long cost = Math.max(0, requiredValue - nums[i]);
            costs[i] = cost;
        }

        // Helper function to solve MWIS on a linear array W, returning all Pareto optimal (Cost, Count) pairs.
        // Since we need AT LEAST K peaks, we track both cost and count.
        List<Result> solveLinearMWIS(long[] W) {
            int N_line = W.length;
            if (N_line == 0) return List.of(new Result(0, 0));

            // dp[i][s] stores the best Result pair for W[0..i] ending in state s.
            // State 0: W[i] is NOT chosen.
            // State 1: W[i] IS chosen.
            // Since we need to track multiple possibilities (different costs for the same count, or different counts for the same cost), 
            // storing just one 'best' state is insufficient. We must store a list of non-dominated results.

            // dp[i][s] = List of Result objects (non-dominated)
            List<Result>[][] dp = new List[N_line][2];
            for (int i = 0; i < N_line; i++) {
                dp[i][0] = new ArrayList<>();
                dp[i][1] = new ArrayList<>();
            }

            // Helper to add a new result, keeping only non-dominated ones
            java.util.function.Consumer<Result> addResult = (newRes) -> {
                List<Result> list = new ArrayList<>();

                // Gather existing non-dominated results
                for (Result res : dp[i][0]) list.add(res);
                for (Result res : dp[i][1]) list.add(res);

                list.add(newRes);

                // Filter for Pareto optimality: 
                // A result R1 dominates R2 if R1.cost <= R2.cost AND R1.count >= R2.count, and at least one inequality is strict.

                List<Result> nonDominated = new ArrayList<>();
                for (Result r1 : list) {
                    boolean dominated = false;
                    for (Result r2 : list) {
                        if (r1 == r2) continue;
                        // r2 dominates r1 if r2 is better or equal in both metrics, and strictly better in at least one.
                        if (r2.cost <= r1.cost && r2.count >= r1.count && (r2.cost < r1.cost || r2.count > r1.count)) {
                            dominated = true;
                            break;
                        }
                    }
                    if (!dominated) {
                        nonDominated.add(r1);
                    }
                }

                // Clear and refill the target DP state
                dp[i][0].clear();
                dp[i][1].clear();

                // In this structure, we need to manage which list (0 or 1) we are modifying, 
                // but since we are abstracting the DP transition logic below, we will just return the final list.
            };

            // Resetting the DP structure to use a simpler transition focusing on minimum cost for required count, 
            // since N is small enough that we might track cost per count.

            // dp[i][j][s] = minimum cost to achieve j peaks in W[0..i] ending in state s.
            // Since K is small (<= N/2), we can afford O(N * K) states.
            int maxK = N_line;
            if (N_line > 0) maxK = Math.min(N_line, (N_line + 1) / 2);


            long[][][] dp_cost = new long[N_line][maxK + 1][2];
            final long INF = Long.MAX_VALUE / 2; // Use half to prevent overflow during addition

            for(int i=0; i<N_line; i++) {
                for(int j=0; j<=maxK; j++) {
                    dp_cost[i][j][0] = INF;
                    dp_cost[i][j][1] = INF;
                }
            }

            // Base Case i=0
            dp_cost[0][0][0] = 0; // 0 peaks, not chosen
            dp_cost[0][1][1] = W[0]; // 1 peak, chosen

            for (int i = 1; i < N_line; i++) {
                for (int j = 0; j <= maxK; j++) {

                    // Case 0: W[i] is NOT chosen.
                    // Transition from i-1 being chosen or not chosen.
                    dp_cost[i][j][0] = Math.min(
                        dp_cost[i-1][j][0], // i-1 not chosen
                        dp_cost[i-1][j][1]  // i-1 chosen
                    );

                    // Case 1: W[i] IS chosen. (Requires i-1 NOT chosen)
                    if (j >= 1) {
                        if (dp_cost[i-1][j-1][0] != INF) {
                            long newCost = dp_cost[i-1][j-1][0] + W[i];
                            dp_cost[i][j][1] = Math.min(dp_cost[i][j][1], newCost);
                        }
                    }
                }
            }

            // Extract results: list of (cost, count) pairs for this linear segment
            List<Result> finalResults = new ArrayList<>();
            for (int j = 0; j <= maxK; j++) {
                long cost0 = dp_cost[N_line - 1][j][0];
                long cost1 = dp_cost[N_line - 1][j][1];

                if (cost0 != INF) finalResults.add(new Result(cost0, j));
                if (cost1 != INF) finalResults.add(new Result(cost1, j));
            }
            return finalResults;
        }

        // --- Case A: Index 0 is NOT a peak ---
        // Solve MWIS for costs[1] to costs[n-1] (N-1 elements)
        long[] costsA = new long[n - 1];
        System.arraycopy(costs, 1, costsA, 0, n - 1);
        List<Result> resultsA_linear = solveLinearMWIS(costsA);

        long minCostA = Long.MAX_VALUE / 2;
        for (Result res : resultsA_linear) {
            if (res.count >= k) {
                minCostA = Math.min(minCostA, res.cost);
            }
        }

        // --- Case B: Index 0 IS a peak ---
        // If 0 is a peak, then 1 and N-1 cannot be peaks.
        // Solve MWIS for costs[2] to costs[N-2] (N-3 elements).
        long minCostB = Long.MAX_VALUE / 2;

        if (n >= 3) {
            int N_B_line = n - 3;
            long[] costsB_linear = new long[N_B_line];
            System.arraycopy(costs, 2, costsB_linear, 0, N_B_line);

            List<Result> resultsB_linear = solveLinearMWIS(costsB_linear);

            // Initial count is 1 (for index 0).
            for (Result res : resultsB_linear) {
                int totalCount = res.count + 1; 
                long totalCost = res.cost + costs[0];

                if (totalCount >= k) {
                    minCostB = Math.min(minCostB, totalCost);
                }
            }
        } else if (n == 2) {
             // n=2, k=1. Both are neighbors. They cannot both be peaks.
             // If k=1, we take min(costs[0], costs[1])
             if (k == 1) {
                 minCostB = Math.min(costs[0], costs[1]);
             }
        }


        long finalMinCost = Math.min(minCostA, minCostB);

        return finalMinCost >= Long.MAX_VALUE / 2 ? -1 : finalMinCost;
    }
}
